SELECT * FROM pet_memories
WHERE pet_id = #{petId} AND memory_key = #{memoryKey}
ORDER BY version DESC LIMIT 1

SELECT * FROM pet_memories
WHERE pet_id = #{petId} AND memory_key = #{memoryKey}
